Module[{h11, h21, h31, b3, chiHodge, chiBetti, isConsistent, nGen, isSquare},
  (* TCS #187 Hodge numbers *)
  h11 = 4;   (* Kahler moduli *)
  h21 = 0;   (* No complex structure for G2 *)
  h31 = 68;  (* Associative 3-cycle moduli *)
  b3 = 24;   (* Third Betti number *)

  (* Method 1: Canonical Hodge number formula *)
  chiHodge = 2*(h11 - h21 + h31);

  (* Method 2: Betti number shortcut *)
  chiBetti = 6*b3;

  (* Consistency of both derivations *)
  isConsistent = (chiHodge == chiBetti);

  (* Generation count: n_gen = chi_eff/48 *)
  nGen = chiHodge/48;

  (* Perfect square check *)
  isSquare = IntegerQ[Sqrt[chiHodge]];

  {chiHodge, isConsistent, nGen, isSquare, "LOCKED"}
]
